{"code": "import json
import re
import os
import pandas as pd

# Step 1: Find all citing patents and their CPC codes
# Load all patents that have citations containing UNIV CALIFORNIA
file_path = '/tmp/tmpz4q1g3x2.json'

with open(file_path, 'r') as f:
    citing_patents_raw = json.load(f)

# Extract unique citing patents and their CPC codes
citing_patents = []
citation_map = {}

for record in citing_patents_raw:
    patents_info = record['Patents_info']
    citation = record['citation']
    cpc = record['cpc']

    # Extract the citing assignee (first assignee mentioned)
    assignee_match = re.search(r'([A-Z][A-Z0-9\s&]+(?:CO|CORP|INC|LLC|LTD|PLC|GMBH|AG|SA|SAS|BV|NV|LIMITED)[A-Z0-9\s]*)', patents_info)
    if assignee_match:
        citing_assignee = assignee_match.group(1).strip()
        # Skip UNIV CALIFORNIA itself
        if 'UNIV CALIFORNIA' in citing_assignee:
            continue
    else:
        continue

    # Parse citation JSON to find which UNIV CALIFORNIA patents are cited
    cited_publication_numbers = []
    if citation and citation != '[]':
        try:
            citations = json.loads(citation)
            for cit in citations:
                pub_num = cit.get('publication_number', '')
                if pub_num:
                    cited_publication_numbers.append(pub_num)
        except:
            # Fallback: extract from string
            matches = re.findall(r'"publication_number":\s*"([^"]+)"', citation)
            cited_publication_numbers.extend(matches)

    # Parse CPC codes
    cpc_codes = []
    if cpc and cpc != '[]':
        try:
            cpc_list = json.loads(cpc)
            for cpc_item in cpc_list:
                code = cpc_item.get('code', '')
                if code:
                    cpc_codes.append(code)
        except:
            matches = re.findall(r'"code":\s*"([^"]+)"', cpc)
            cpc_codes.extend(matches)

    if cited_publication_numbers and cpc_codes:
        # Store primary CPC (first one)
        primary_cpc = cpc_codes[0] if cpc_codes else None

        citing_patents.append({
            'citing_assignee': citing_assignee,
            'cited_publications': cited_publication_numbers,
            'primary_cpc': primary_cpc,
            'all_cpc_codes': cpc_codes
        })

# Count citations per assignee
assignee_citations = {}
for cp in citing_patents:
    assignee = cp['citing_assignee']
    if assignee not in assignee_citations:
        assignee_citations[assignee] = {
            'citation_count': 0,
            'cited_pubs': set(),
            'cpc_codes': set()
        }
    assignee_citations[assignee]['citation_count'] += 1
    assignee_citations[assignee]['cited_pubs'].update(cp['cited_publications'])
    assignee_citations[assignee]['cpc_codes'].add(cp['primary_cpc'])

# Get unique CPC codes to lookup
unique_cpc_codes = set()
for info in assignee_citations.values():
    for cpc in info['cpc_codes']:
        if cpc:
            unique_cpc_codes.add(cpc)

print('__RESULT__:')
print(json.dumps({
    'citing_assignee_count': len(assignee_citations),
    'unique_cpc_codes': list(unique_cpc_codes)[:20],  # First 20
    'top_assignees': list(assignee_citations.keys())[:10]
}))"}

